// Comprehensive form validation
const input = $input.first().json || {};
const body = input.body || input;

// Define required and optional fields
const requiredFields = $env.REQUIRED_FORM_FIELDS ? $env.REQUIRED_FORM_FIELDS.split(',') : ['name', 'email', 'message'];
const optionalFields = $env.OPTIONAL_FORM_FIELDS ? $env.OPTIONAL_FORM_FIELDS.split(',') : ['phone', 'company'];
const maxFieldLengths = {
  name: 100,
  email: 254,
  message: 5000,
  phone: 50,
  company: 100
};

const errors = [];
const validated = {};

// Check required fields
for (const field of requiredFields) {
  const value = body[field];
  if (value === undefined || value === null || value === '') {
    errors.push(`Missing required field: ${field}`);
  } else {
    validated[field] = value;
  }
}

// Validate field lengths
for (const [field, value] of Object.entries(validated)) {
  const maxLength = maxFieldLengths[field] || 1000;
  if (typeof value === 'string' && value.length > maxLength) {
    errors.push(`${field} exceeds maximum length of ${maxLength} characters`);
  }
}

// Validate email format if present
if (validated.email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(validated.email)) {
    errors.push('Invalid email format');
  }
}

// Validate phone if present (basic format) - only add if validation passes
if (body.phone) {
  const phoneRegex = /^[\d\s\-\+\(\)\.]{7,50}$/;
  const phoneValue = body.phone;
  if (phoneValue.length > maxFieldLengths.phone) {
    errors.push(`Phone exceeds maximum length of ${maxFieldLengths.phone} characters`);
  } else if (!phoneRegex.test(phoneValue)) {
    errors.push('Invalid phone format');
  } else {
    validated.phone = phoneValue;
  }
}

// Add optional fields with length validation
for (const field of optionalFields) {
  if (body[field] !== undefined && body[field] !== '') {
    const maxLength = maxFieldLengths[field] || 1000;
    if (typeof body[field] === 'string' && body[field].length > maxLength) {
      errors.push(`${field} exceeds maximum length of ${maxLength} characters`);
    } else {
      validated[field] = body[field];
    }
  }
}

// Add metadata with cryptographically secure submission ID
validated._submitted_at = new Date().toISOString();
// Use crypto.randomUUID() for secure random ID generation (available in n8n code node v2)
validated._submission_id = typeof require !== 'undefined' ? require('crypto').randomUUID() : Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      errors: errors,
      submission_id: validated._submission_id
    }
  }];
}

return [{
  json: {
    valid: true,
    data: validated,
    submission_id: validated._submission_id
  }
}];

// Handle LLM response with error checking
const input = $input.first().json || {};

// Check if previous node failed (continueOnFail: true)
if (input.error) {
  return [{
    json: {
      success: false,
      llm_error: input.error,
      fallback: 'Form data saved without LLM processing',
      data: $('Validate Form').item.json.data || {}
    }
  }];
}

const choice = input.choices?.[0];
const content = choice?.message?.content || 'No response';

return [{
  json: {
    success: true,
    llm_response: content,
    model_used: input.model || 'unknown',
    tokens_used: input.usage?.total_tokens || 0
  }
}];

